"use client";
import React from 'react';
import Categorybar from '../../components/Categorybar';
import styles from '../../CSS/home.module.css';
import Image from 'next/image';
import Navbar from '../../components/Navbar';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';

const Home = () => {
    const [hotels, setHotels] = useState([]);
    const [filteredHotels, setFilteredHotels] = useState([]);
    const [facilities, setFacilities] = useState({
        wifi: true,
        spa: true,
        food: false,
        telephone: false,
        gym: false,
        kitchen: false
    });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const router = useRouter();

    // Fetch hotels from the API
    useEffect(() => {
        async function loadHotels() {
            try {
                const res = await fetch('http://localhost:5000/api/hotels');
                console.log('[Home] fetch status:', res.status);
                if (!res.ok) throw new Error(`HTTP ${res.status}`);
                const data = await res.json();
                setHotels(data);
                setFilteredHotels(data); // Initially show all hotels
            } catch (err) {
                console.error('Failed to fetch hotels:', err);
                setError('Unable to load hotels.');
            } finally {
                setLoading(false);
            }
        }
        loadHotels();
    }, []); // Fetch data when component mounts

    // Filter hotels based on selected facilities
    const filterDestinationsByFacilities = () => {
        const filtered = hotels.filter(destination => {
            for (let key in facilities) {
                if (facilities[key] && !destination.facilities[key]) {
                    return false; // If the hotel doesn't have a required facility, exclude it
                }
            }
            return true;
        });
        setFilteredHotels(filtered);
    };

    // Call filter function when facilities change (optional if you have facility filters)
    // You can add a UI for filtering based on the facilities (checkboxes, dropdown, etc.)

    const handleCategoryClick = (category) => {
        console.log("Category clicked:", category);
        router.push(`/home/${category}`);
    };

    if (loading) return <p>Loading hotels...</p>;
    if (error) return <p>{error}</p>;

    return (
        <>
            <div className={styles.container}>
                <header className={styles.header}>
                    <Navbar />
                </header>
                <Categorybar onCategoryClick={handleCategoryClick} />

                {/* Optional: Add a button or UI for filtering */}
                <button onClick={filterDestinationsByFacilities}>Filter by Facilities</button>

                <div className={styles.destinationsGrid}>
                    {filteredHotels.map((destination) => (
                        <div key={destination.id} className={styles.destinationCard}>
                            <div className={styles.cardImage}>
                                <Image
                                    src={destination.thumbnailImage}
                                    alt={destination.location}
                                    layout="fill"
                                    objectFit="cover"
                                    placeholder="blur"
                                    blurDataURL="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+P+/HgAFeAJ5N1EZEAAAAABJRU5ErkJggg=="
                                />
                            </div>
                            <div className={styles.cardContent}>
                                <h3 className={styles.location}>{destination.location}</h3>
                                <p className={styles.price}>{destination.price}</p>
                                <div className={styles.ratingStars}>
                                    {[...Array(5)].map((_, i) => (
                                        <span key={i} className={i < destination.rating ? styles.starFilled : styles.starEmpty}>★</span>
                                    ))}
                                </div>
                                <div className={styles.viewDetail}>
                                    <div className={styles.viewContent}>View Details</div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </>
    );
};

export default Home;